파일 경로: `app/src/main/kotlin/com/maum/backend/service/user/UserService.kt`

```kotlin
// AFTER: UserService - 캐시 전략 적용
@Service
@Transactional(readOnly = true)
class UserService(
    private val userRepository: UserRepository,
) {
    companion object {
        const val CACHE_NAME = "user:nickname"
        const val CACHE_TTL_SECONDS = 300L  // 5분 TTL
    }

    // 닉네임으로 유저 조회 - Redis 캐시 적용
    // key: "user:nickname::{nickname}", TTL: 5분
    @Cacheable(
        cacheNames = [CACHE_NAME],
        key = "#nickname",
        unless = "#result == null"  // null 결과는 캐시하지 않음
    )
    fun findByNickname(nickname: String): User? {
        return userRepository.findByNickname(nickname)
    }

    // 유저 정보 업데이트 시 캐시 무효화
    @CacheEvict(cacheNames = [CACHE_NAME], key = "#nickname")
    @Transactional
    fun updateUserNickname(userId: String, oldNickname: String, newNickname: String): User {
        val user = userRepository.findById(userId)
            .orElseThrow { IllegalArgumentException("유저를 찾을 수 없습니다: $userId") }
        // 업데이트 로직
        return userRepository.save(user)
    }

    // 유저 삭제 시 캐시 무효화
    @CacheEvict(cacheNames = [CACHE_NAME], key = "#nickname")
    @Transactional
    fun deleteUser(userId: String, nickname: String) {
        userRepository.deleteById(userId)
    }
}
```

