### 3-3. Redis 캐시 설정 (TTL + 직렬화)

파일 경로: `app/src/main/kotlin/com/maum/backend/config/CacheConfig.kt`

```kotlin
// AFTER: Redis 캐시 설정 - TTL 및 직렬화 전략
@Configuration
@EnableCaching
class CacheConfig(
    private val redisConnectionFactory: RedisConnectionFactory,
) {
    @Bean
    fun cacheManager(): RedisCacheManager {
        val defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .serializeKeysWith(
                RedisSerializationContext.SerializationPair.fromSerializer(StringRedisSerializer())
            )
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(
                    GenericJackson2JsonRedisSerializer()
                )
            )
            .disableCachingNullValues()  // null 값 캐시 방지

        val cacheConfigurations = mapOf(
            // user:nickname 캐시: TTL 5분
            // 닉네임은 자주 변경되지 않으므로 적절한 TTL
            "user:nickname" to defaultConfig.entryTtl(Duration.ofSeconds(300)),

            // user:id 캐시: TTL 10분 (ID 기반은 변경 빈도 더 낮음)
            "user:id" to defaultConfig.entryTtl(Duration.ofMinutes(10)),
        )

        return RedisCacheManager.builder(redisConnectionFactory)
            .cacheDefaults(defaultConfig)
            .withInitialCacheConfigurations(cacheConfigurations)
            .build()
    }
}
```

